"""Tests for agentic AI utilities."""import osimport pytestfrom unittest.mock import patch, mock_openfrom agentic_ai.utils import (    get_required_env,    get_optional_env,    load_system_message,    validate_api_key)class TestEnvironmentUtils:    """Test environment utility functions."""    def test_get_required_env_success(self):        """Test successful retrieval of required environment variable."""        with patch.dict(os.environ, {'TEST_VAR': 'test_value'}):            result = get_required_env('TEST_VAR')            assert result == 'test_value'    def test_get_required_env_missing(self):        """Test that missing required env var raises RuntimeError."""        with patch.dict(os.environ, {}, clear=True):            with pytest.raises(RuntimeError, match="TEST_VAR environment variable not found"):                get_required_env('TEST_VAR')    def test_get_optional_env_with_value(self):        """Test optional env var retrieval when value exists."""        with patch.dict(os.environ, {'OPTIONAL_VAR': 'optional_value'}):            result = get_optional_env('OPTIONAL_VAR', 'default')            assert result == 'optional_value'    def test_get_optional_env_with_default(self):        """Test optional env var retrieval when using default."""        with patch.dict(os.environ, {}, clear=True):            result = get_optional_env('MISSING_VAR', 'default_value')            assert result == 'default_value'class TestFileUtils:    """Test file utility functions."""    def test_load_system_message_success(self):        """Test successful loading of system message file."""        mock_content = "This is a test system message."        with patch("builtins.open", mock_open(read_data=mock_content)):            result = load_system_message("test_file.txt")            assert result == mock_content    def test_load_system_message_file_not_found(self):        """Test handling of missing system message file."""        with patch("builtins.open", side_effect=FileNotFoundError):            with pytest.raises(RuntimeError, match="System message file 'missing.txt' not found"):                load_system_message("missing.txt")class TestAPIKeyValidation:    """Test API key validation."""    def test_validate_api_key_from_env(self):        """Test API key validation from environment."""        with patch.dict(os.environ, {'ANTHROPIC_API_KEY': 'test_key'}):            result = validate_api_key()            assert result == 'test_key'    def test_validate_api_key_missing(self):        """Test API key validation when missing."""        with patch.dict(os.environ, {}, clear=True):            with pytest.raises(RuntimeError, match="ANTHROPIC_API_KEY not found"):                validate_api_key()    def test_validate_api_key_provided(self):        """Test API key validation when provided directly."""        result = validate_api_key("provided_key")        assert result == "provided_key"